// Assemble the single-transaction SQL from the bundle. §234: all-or-nothing.
// NOTE: values are embedded for readability; migrate to parameterized query fields
// before production (documented risk).
const b = $('When Executed by WF-001').first().json;
const q = (s)=> String(s==null?'':s).replace(/'/g, "''");   // minimal escaping
const stmts = [];
stmts.push('BEGIN;');
stmts.push(`UPDATE repository.documents SET status='PROCESSED' WHERE id='${q(b.documentId)}';`);
for (const m of (b.metadata||[])) stmts.push(`INSERT INTO repository.metadata (document_id,key,value) VALUES ('${q(b.documentId)}','${q(m.key)}','${q(m.value)}');`);
for (const k of (b.accepted||b.acceptedUnits||[])) stmts.push(`INSERT INTO repository.knowledge_units (id,document_id,content,category,authority,status) VALUES ('${q(k.id)}','${q(b.documentId)}','${q(k.statement)}','${q(k.category)}','${q(k.authoritySource)}','Draft');`);
for (const e of (b.evidence||[])) stmts.push(`INSERT INTO repository.evidence (id,knowledge_unit_id,excerpt) VALUES ('${q(e.id)}','${q(e.knowledgeUnitId)}','${q(e.excerpt)}');`);
for (const c of (b.citations||[])) stmts.push(`INSERT INTO repository.citations (id,evidence_id,document_id,page,section) VALUES ('${q(c.id)}','${q(c.evidenceId)}','${q(b.documentId)}',${c.page==null?'NULL':Number(c.page)},'${q(c.section)}');`);
for (const ch of (b.chunks||[])) stmts.push(`INSERT INTO repository.retrieval_chunks (id,knowledge_unit_id,chunk_order,content) VALUES ('${q(ch.id)}','${q(ch.knowledgeUnitId)}',${Number(ch.ordinal||0)},'${q(ch.text)}');`);
for (const em of (b.embeddings||[])) stmts.push(`INSERT INTO repository.embeddings (id,chunk_id,embedding) VALUES ('${q(em.id||'')}','${q(em.chunkId)}','[${(em.vector||[]).join(',')}]');`);
stmts.push('COMMIT;');
return [{ json: { _txn: stmts.join('\n'),
  _counts: { knowledgeUnits:(b.accepted||b.acceptedUnits||[]).length, evidence:(b.evidence||[]).length,
             citations:(b.citations||[]).length, chunks:(b.chunks||[]).length, embeddings:(b.embeddings||[]).length } } }];

// Enrichment: preserve incoming item, add { written, ...counts }.
const incoming = $('When Executed by WF-001').first().json;
return [{ json: { ...incoming, written: true, ...$('Build Transaction').first().json._counts } }];
